"""
Logo in base64 format for the application.
"""
LOGO_BASE64 = """"""

def get_pixmap_from_base64(base64_str):
    """Convert base64 string to QPixmap."""
    from PyQt6.QtCore import QByteArray
    from PyQt6.QtGui import QPixmap
    data = QByteArray.fromBase64(base64_str.encode())
    pixmap = QPixmap()
    pixmap.loadFromData(data)
    return pixmap
